10.query:
timeseries request_count = sum(cloud.gcp.apigee_googleapis_com.proxyv2.request_count),by:{env,proxy_name}
| filter matchesValue(env, $Domain)  
| filter matchesValue(proxy_name, $Proxy)

19.query:
timeseries bdb_no_of_keys = sum(bdb_no_of_keys, rollup: total), by:{bdb_name, cluster}
| filter in(bdb_name,$RedisEnvironment)
| fieldsAdd cluster = if(cluster == "mc1087-0.us-central1-mz.gcp.cloud.rlrcp.com", "Central DB", else: "East DB")

variables.input:
timeseries max(bdb_up), by: { bdb_name }
| fieldsAdd bdb_name
| fieldsKeep bdb_name
| filter if(in("azpr1-infra-apigee-prod", $Environment) and in("azpr1-infr-apigee", $Environment), matchesPhrase(bdb_name, "tech-apigee-redis"),
      else: if(in("azpr1-infra-apigee-prod", $Environment) and not in("azpr1-infr-apigee", $Environment), startsWith(bdb_name, "azpr-tech-apigee-redis") , else: startsWith(bdb_name, "azdv-tech-apigee-redis") or startsWith(bdb_name, "azqa-tech-apigee-redis") or startsWith(bdb_name, "azst-tech-apigee-redis")))
